"use client";

import React, { useState, useEffect } from "react";
import {
  LayoutDashboard,
  Package,
  Search,
  CheckCircle,
  AlertCircle,
  Users,
  ClipboardList,
  RefreshCw,
  Clock,
  ChevronRight,
  ShieldCheck,
} from "lucide-react";

export default function AdminDashboard() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchDashboardData = async () => {
    setLoading(true);
    setError(null);
    try {
      const token = localStorage.getItem("accessToken");
      const res = await fetch("http://localhost:5000/admin/dashboard", {
        headers: { Authorization: `Bearer ${token}` },
      });

      const result = await res.json();
      if (!res.ok) throw new Error(result.message || "Unauthorized access");

      setData(result);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchDashboardData();
  }, []);

  if (loading)
    return (
      <div className="flex h-screen w-full items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center gap-4">
          <div className="h-12 w-12 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
          <p className="text-xs font-black uppercase tracking-widest text-slate-400">
            Loading Analytics...
          </p>
        </div>
      </div>
    );

  if (error || !data)
    return (
      <div className="flex h-screen w-full items-center justify-center p-6">
        <div className="max-w-md text-center bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-xl">
          <AlertCircle className="mx-auto text-rose-500 mb-4" size={48} />
          <h2 className="text-xl font-black text-slate-800">Sync Error</h2>
          <p className="text-slate-500 mt-2">{error}</p>
          <button
            onClick={fetchDashboardData}
            className="mt-6 px-8 py-3 bg-indigo-600 text-white rounded-2xl font-bold flex items-center gap-2 mx-auto"
          >
            <RefreshCw size={18} /> Retry
          </button>
        </div>
      </div>
    );

  // MAPPING TO YOUR SPECIFIC API JSON STRUCTURE
  const { users, items, claims } = data;

  return (
    <div className="min-h-screen bg-[#f8fafc] p-8">
      <div className="max-w-[1400px] mx-auto space-y-8">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">
              Dashboard Overview
            </h1>
            <p className="text-slate-500 font-medium">
              Real-time statistics for items and users.
            </p>
          </div>
          <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-4 px-4">
            <div className="flex flex-col items-end">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                Admin Access
              </span>
              <span className="text-sm font-bold text-slate-700">
                Verified System
              </span>
            </div>
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-100">
              <ShieldCheck size={20} />
            </div>
          </div>
        </div>

        {/* Stats Grid - Mapping your exact API keys */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          {/* Items Total */}
          <div className="bg-white p-7 rounded-[2rem] border border-slate-100 shadow-sm relative overflow-hidden group">
            <div className="absolute -right-4 -top-4 text-slate-50 opacity-10 group-hover:scale-110 transition-transform duration-500">
              <Package size={120} />
            </div>
            <div className="bg-blue-50 text-blue-600 w-12 h-12 rounded-2xl flex items-center justify-center mb-4">
              <Package size={24} />
            </div>
            <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">
              Total Items
            </p>
            <h3 className="text-4xl font-black text-slate-800 mt-1">
              {items.total}
            </h3>
            <div className="mt-4 flex gap-2">
              <span className="text-[10px] font-bold px-2 py-0.5 bg-amber-50 text-amber-600 rounded-md">
                Pending: {items.pending}
              </span>
              <span className="text-[10px] font-bold px-2 py-0.5 bg-emerald-50 text-emerald-600 rounded-md">
                Returned: {items.returned}
              </span>
            </div>
          </div>

          {/* Claims Statistics */}
          <div className="bg-white p-7 rounded-[2rem] border border-slate-100 shadow-sm relative overflow-hidden group">
            <div className="bg-indigo-50 text-indigo-600 w-12 h-12 rounded-2xl flex items-center justify-center mb-4">
              <ClipboardList size={24} />
            </div>
            <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">
              Total Claims
            </p>
            <h3 className="text-4xl font-black text-slate-800 mt-1">
              {claims.total}
            </h3>
            <div className="mt-4 flex gap-2">
              <span className="text-[10px] font-bold px-2 py-0.5 bg-emerald-50 text-emerald-600 rounded-md">
                Approved: {claims.approved}
              </span>
              <span className="text-[10px] font-bold px-2 py-0.5 bg-rose-50 text-rose-600 rounded-md">
                Rejected: {claims.rejected}
              </span>
            </div>
          </div>

          {/* User Metrics */}
          <div className="bg-white p-7 rounded-[2rem] border border-slate-100 shadow-sm relative overflow-hidden group">
            <div className="bg-emerald-50 text-emerald-600 w-12 h-12 rounded-2xl flex items-center justify-center mb-4">
              <Users size={24} />
            </div>
            <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">
              Platform Users
            </p>
            <h3 className="text-4xl font-black text-slate-800 mt-1">
              {users.total}
            </h3>
            <div className="mt-4 flex gap-2">
              <span className="text-[10px] font-bold px-2 py-0.5 bg-slate-100 text-slate-600 rounded-md">
                Admins: {users.admins}
              </span>
              <span className="text-[10px] font-bold px-2 py-0.5 bg-blue-50 text-blue-600 rounded-md">
                Verified: {users.verified}
              </span>
            </div>
          </div>

          {/* Success Rate Calculation */}
          <div className="bg-indigo-600 p-7 rounded-[2rem] shadow-xl shadow-indigo-100 relative overflow-hidden">
            <div className="relative z-10">
              <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200">
                Return Success
              </p>
              <h3 className="text-4xl font-black text-white mt-1">
                {Math.round((items.returned / (items.total || 1)) * 100)}%
              </h3>
              <p className="text-xs text-indigo-100 mt-4 font-medium leading-relaxed">
                Percentage of found items successfully returned to owners.
              </p>
            </div>
            <div className="absolute right-[-20px] bottom-[-20px] opacity-20">
              <CheckCircle size={140} className="text-white" />
            </div>
          </div>
        </div>

        {/* Secondary Info Section */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
            <h4 className="font-black text-slate-800 uppercase tracking-widest text-xs mb-6 flex items-center gap-2">
              <Clock size={16} className="text-indigo-600" />
              Item Verification Status
            </h4>
            <div className="space-y-4">
              <div className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                <span className="text-sm font-bold text-slate-600">
                  Items Pending Approval
                </span>
                <span className="bg-amber-100 text-amber-700 px-3 py-1 rounded-lg font-black text-sm">
                  {items.pending}
                </span>
              </div>
              <div className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                <span className="text-sm font-bold text-slate-600">
                  Active Claims in Queue
                </span>
                <span className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-lg font-black text-sm">
                  {claims.pending}
                </span>
              </div>
            </div>
          </div>

          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white flex flex-col justify-between group">
            <div>
              <h4 className="font-black uppercase tracking-widest text-[10px] text-slate-400 mb-2">
                Quick Actions
              </h4>
              <h3 className="text-2xl font-black">Needs Attention</h3>
              <p className="text-slate-400 mt-2 text-sm leading-relaxed">
                There are{" "}
                <span className="text-white font-bold">
                  {items.pending} items
                </span>{" "}
                and{" "}
                <span className="text-white font-bold">
                  {claims.pending} claims
                </span>{" "}
                that require your verification to proceed.
              </p>
            </div>
            <button className="mt-8 flex items-center justify-between w-full p-4 bg-white/10 hover:bg-white/20 transition-colors rounded-2xl group">
              <span className="font-bold text-sm">Open Verification Panel</span>
              <ChevronRight
                size={20}
                className="group-hover:translate-x-1 transition-transform"
              />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
